  d['en']['rm.challenges_title']='The Risks You Face Today';
  d['en']['rm.challenges_desc']='Modern businesses navigate an increasingly complex risk landscape. Without a proactive approach, these challenges can erode value, expose your organization to regulatory penalties, and undermine stakeholder confidence.';
  d['en']['rm.challenge_1_title']='Incomplete Risk Visibility';
  d['en']['rm.challenge_1_desc']='Blind spots in risk identification leave organizations vulnerable to unforeseen threats.';
  d['en']['rm.challenge_2_title']='Weak Internal Controls';
  d['en']['rm.challenge_2_desc']='Inadequate control environments allow errors, inefficiencies, and fraud to persist undetected.';
  d['en']['rm.challenge_3_title']='Regulatory Compliance Gaps';
  d['en']['rm.challenge_3_desc']='Evolving regulations demand continuous monitoring and adaptation to remain compliant.';
  d['en']['rm.challenge_4_title']='Inadequate Governance';
  d['en']['rm.challenge_4_desc']='Weak governance structures compromise decision-making quality and accountability.';
  d['en']['rm.challenge_5_title']='No Business Continuity Approach';
  d['en']['rm.challenge_5_desc']='Without continuity planning, disruptions can cascade into prolonged operational failures.';
